// csv-parser.ts — A robust CSV parser library in TypeScript

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface CSVOptions {
  /** Field delimiter (default: ",") */
  delimiter?: string;
  /** Quote character (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \r, or \n) */
  lineSeparator?: string;
  /** Whether to perform automatic type coercion (default: true) */
  typeCoercion?: boolean;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  /** Parsed rows as plain objects keyed by header names */
  rows: Record<string, unknown>[];
  /** Column header names derived from the first row */
  headers: string[];
  /** Errors collected during parsing (malformed rows, etc.) */
  errors: CSVError[];

  /** Return only rows matching the predicate */
  filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[];
  /** Sum all numeric values in the given column */
  sum(column: string): number;
  /** Average of all numeric values in the given column */
  average(column: string): number;
  /** Total number of data rows */
  count(): number;
  /** Group rows by the values of a column, returning a Map */
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/**
 * Parse a single logical line into an array of string field values,
 * respecting the configured quote character.
 *
 * Returns `null` when the line is empty / whitespace-only so that it can be
 * silently skipped (trailing blank lines are common).
 */
function parseRow(
  line: string,
  delimiter: string,
  quote: string
): { fields: string[]; error?: string } | null {
  // Completely empty line → skip
  if (line.length === 0) return null;

  const fields: string[] = [];
  let i = 0;

  while (i <= line.length) {
    if (i === line.length) {
      // Trailing delimiter produced an empty field at end
      // Only add if we already pushed at least one field AND the previous char
      // was a delimiter (handled naturally by the loop logic below).
      break;
    }

    if (line[i] === quote) {
      // ---- Quoted field ----
      i++; // skip opening quote
      let value = "";
      let closed = false;
      while (i < line.length) {
        if (line[i] === quote) {
          // Could be escaped quote ("") or closing quote
          if (i + 1 < line.length && line[i + 1] === quote) {
            value += quote;
            i += 2;
          } else {
            // Closing quote
            i++; // skip closing quote
            closed = true;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }

      if (!closed) {
        // Unterminated quoted field – we still return what we have but flag
        // it as an error.
        fields.push(value);
        return { fields, error: "Unterminated quoted field" };
      }

      fields.push(value);

      // After closing quote we expect either delimiter or end-of-line
      if (i < line.length) {
        if (line[i] === delimiter) {
          i++; // consume delimiter
          // If delimiter is the very last character, push an empty trailing field
          if (i === line.length) {
            fields.push("");
          }
        } else {
          // Garbage after closing quote – we'll still continue but flag error
          // Consume up to next delimiter
          let junk = "";
          while (i < line.length && line[i] !== delimiter) {
            junk += line[i];
            i++;
          }
          // Append the junk to the last field value (lenient)
          fields[fields.length - 1] += junk;
          if (i < line.length) {
            i++; // skip delimiter
            if (i === line.length) {
              fields.push("");
            }
          }
          // We don't flag this as a hard error; it's "weird" but recoverable
        }
      }
    } else {
      // ---- Unquoted field ----
      let value = "";
      while (i < line.length && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);
      if (i < line.length) {
        i++; // skip delimiter
        // Trailing delimiter → empty field
        if (i === line.length) {
          fields.push("");
        }
      }
    }
  }

  return { fields };
}

/**
 * Coerce a raw string value to its detected JS type.
 */
function coerce(value: string): unknown {
  // Null / empty
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Boolean (case-insensitive)
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number – must be the entire string, not just a prefix
  if (/^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(value.trim())) {
    const num = Number(value);
    if (!Number.isNaN(num)) return num;
  }

  return value;
}

/**
 * Split raw input into logical lines.
 *
 * When the caller supplies an explicit `lineSeparator` we use it directly.
 * Otherwise we auto-detect \r\n → \r → \n.
 *
 * **Important**: splitting must be aware of quoted fields that embed newline
 * characters.  We therefore walk the string character-by-character.
 */
function splitLines(input: string, lineSep: string | undefined, quote: string): string[] {
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  // Determine effective separator
  const sep = lineSep ?? detectLineSeparator(input);

  while (i < input.length) {
    // Toggle quoting state
    if (input[i] === quote) {
      // Check for escaped quote
      if (inQuotes && i + 1 < input.length && input[i + 1] === quote) {
        current += input[i] + input[i + 1];
        i += 2;
        continue;
      }
      inQuotes = !inQuotes;
      current += input[i];
      i++;
      continue;
    }

    if (!inQuotes && input.startsWith(sep, i)) {
      lines.push(current);
      current = "";
      i += sep.length;
      continue;
    }

    current += input[i];
    i++;
  }

  // Push last segment (may be empty for trailing newline)
  lines.push(current);

  return lines;
}

function detectLineSeparator(input: string): string {
  // Walk only up to first newline-ish character, staying outside quotes
  let inQuotes = false;
  for (let i = 0; i < input.length; i++) {
    if (input[i] === '"') {
      if (inQuotes && i + 1 < input.length && input[i + 1] === '"') {
        i++;
        continue;
      }
      inQuotes = !inQuotes;
      continue;
    }
    if (!inQuotes) {
      if (input[i] === "\r") {
        return i + 1 < input.length && input[i + 1] === "\n" ? "\r\n" : "\r";
      }
      if (input[i] === "\n") return "\n";
    }
  }
  return "\n"; // default
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const shouldCoerce = options?.typeCoercion !== false;

  const errors: CSVError[] = [];
  const rows: Record<string, unknown>[] = [];

  // Handle empty / whitespace-only input
  if (input.trim().length === 0) {
    return buildResult([], [], errors);
  }

  // Split into logical lines (respecting quoted newlines)
  const lines = splitLines(input, lineSeparator, quote);

  // ---- Parse header row ----
  const headerResult = parseRow(lines[0], delimiter, quote);
  if (!headerResult || headerResult.fields.length === 0) {
    return buildResult([], [], [{ row: 0, message: "Missing or empty header row" }]);
  }
  if (headerResult.error) {
    errors.push({ row: 0, message: `Header row: ${headerResult.error}` });
  }
  const headers = headerResult.fields.map((h) => h.trim());

  // ---- Parse data rows ----
  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];

    // Skip truly empty trailing lines
    if (line.length === 0 && idx === lines.length - 1) continue;
    // Skip blank lines in the middle too
    if (line.trim().length === 0) continue;

    const result = parseRow(line, delimiter, quote);
    if (result === null) continue;

    if (result.error) {
      errors.push({ row: idx, message: result.error });
      // Still try to build a partial row from whatever fields we got
    }

    const fields = result.fields;

    if (fields.length !== headers.length) {
      errors.push({
        row: idx,
        message: `Column count mismatch: expected ${headers.length}, got ${fields.length}`,
      });
      // Build partial / padded row anyway so data isn't lost
    }

    const row: Record<string, unknown> = {};
    for (let c = 0; c < headers.length; c++) {
      const raw = c < fields.length ? fields[c] : "";
      row[headers[c]] = shouldCoerce ? coerce(raw) : raw;
    }
    rows.push(row);
  }

  return buildResult(headers, rows, errors);
}

// ---------------------------------------------------------------------------
// Result builder (attaches methods)
// ---------------------------------------------------------------------------

function buildResult(
  headers: string[],
  rows: Record<string, unknown>[],
  errors: CSVError[]
): CSVResult {
  return {
    headers,
    rows,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

// csv-parser.test.ts — Comprehensive tests for the CSV parser library
// No external test framework — plain assertions that throw on failure.

import { parseCSV, CSVResult } from "./csv-parser";

// ---------------------------------------------------------------------------
// Tiny test harness
// ---------------------------------------------------------------------------

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, msg: string): void {
  if (!condition) throw new Error(`Assertion failed: ${msg}`);
}

function assertStrictEqual<T>(actual: T, expected: T, label: string): void {
  if (actual !== expected) {
    throw new Error(
      `${label} — expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`
    );
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual, replacer);
  const b = JSON.stringify(expected, replacer);
  if (a !== b) {
    throw new Error(`${label}\n  expected: ${b}\n  actual:   ${a}`);
  }
}

// JSON.stringify replacer that handles Map, undefined, etc.
function replacer(_key: string, value: unknown): unknown {
  if (value instanceof Map) {
    return Object.fromEntries(value.entries());
  }
  return value;
}

function test(name: string, fn: () => void): void {
  try {
    fn();
    passed++;
    console.log(`  ✅ ${name}`);
  } catch (err: any) {
    failed++;
    const msg = `  ❌ ${name}: ${err.message}`;
    failures.push(msg);
    console.log(msg);
  }
}

function section(title: string): void {
  console.log(`\n── ${title} ${"─".repeat(60 - title.length)}`);
}

// ===========================================================================
// TESTS
// ===========================================================================

// ---------------------------------------------------------------------------
section("Basic Parsing");
// ---------------------------------------------------------------------------

test("parses simple CSV with headers", () => {
  const csv = "name,age,city\nAlice,30,NYC\nBob,25,LA";
  const result = parseCSV(csv);

  assertStrictEqual(result.headers.length, 3, "header count");
  assertDeepEqual(result.headers, ["name", "age", "city"], "headers");
  assertStrictEqual(result.rows.length, 2, "row count");
  assertDeepEqual(result.rows[0], { name: "Alice", age: 30, city: "NYC" }, "row 0");
  assertDeepEqual(result.rows[1], { name: "Bob", age: 25, city: "LA" }, "row 1");
  assertStrictEqual(result.errors.length, 0, "no errors");
});

test("handles Windows-style line endings (\\r\\n)", () => {
  const csv = "a,b\r\n1,2\r\n3,4";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertDeepEqual(result.rows[0], { a: 1, b: 2 }, "row 0");
  assertDeepEqual(result.rows[1], { a: 3, b: 4 }, "row 1");
});

test("handles old Mac line endings (\\r)", () => {
  const csv = "x,y\r10,20\r30,40";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertDeepEqual(result.rows[0], { x: 10, y: 20 }, "row 0");
});

test("trims header names", () => {
  const csv = " name , age \nAlice,30";
  const result = parseCSV(csv);
  assertDeepEqual(result.headers, ["name", "age"], "trimmed headers");
});

test("trailing newline does not create an extra row", () => {
  const csv = "a,b\n1,2\n";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 1, "row count");
});

// ---------------------------------------------------------------------------
section("Quoted Fields");
// ---------------------------------------------------------------------------

test("handles quoted fields that contain commas", () => {
  const csv = 'name,address\nAlice,"123 Main St, Apt 4"\nBob,"456 Oak Ave, Suite 7"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["address"], "123 Main St, Apt 4", "address with comma");
  assertStrictEqual(result.rows[1]["address"], "456 Oak Ave, Suite 7", "address with comma");
});

test("handles quoted fields that contain newlines", () => {
  const csv = 'name,bio\nAlice,"Line 1\nLine 2"\nBob,simple';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertStrictEqual(result.rows[0]["bio"], "Line 1\nLine 2", "bio with newline");
  assertStrictEqual(result.rows[1]["bio"], "simple", "simple bio");
});

test("quoted field at beginning and end of row", () => {
  const csv = '"greeting",middle,"farewell"\n"hello",x,"bye"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["greeting"], "hello", "first field quoted");
  assertStrictEqual(result.rows[0]["farewell"], "bye", "last field quoted");
});

test("empty quoted field", () => {
  const csv = 'a,b\n"",value';
  const result = parseCSV(csv);
  // An empty quoted string should coerce to null (same as empty string)
  assertStrictEqual(result.rows[0]["a"], null, "empty quoted field → null");
});

// ---------------------------------------------------------------------------
section("Escaped Quotes");
// ---------------------------------------------------------------------------

test("double-double-quotes inside quoted field become single quote", () => {
  const csv = 'text\n"She said ""hello"""\n"A ""B"" C"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["text"], 'She said "hello"', "escaped quotes 1");
  assertStrictEqual(result.rows[1]["text"], 'A "B" C', "escaped quotes 2");
});

test("field that is just escaped quotes", () => {
  const csv = 'val\n""""""';
  // """""" → content is "" → literal: ""
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], '""', "only escaped quotes");
});

// ---------------------------------------------------------------------------
section("Custom Delimiters");
// ---------------------------------------------------------------------------

test("tab-separated values", () => {
  const csv = "name\tage\nAlice\t30";
  const result = parseCSV(csv, { delimiter: "\t" });
  assertStrictEqual(result.rows[0]["name"], "Alice", "TSV name");
  assertStrictEqual(result.rows[0]["age"], 30, "TSV age");
});

test("semicolon delimiter", () => {
  const csv = "a;b;c\n1;2;3";
  const result = parseCSV(csv, { delimiter: ";" });
  assertDeepEqual(result.rows[0], { a: 1, b: 2, c: 3 }, "semicolon row");
});

test("pipe delimiter", () => {
  const csv = "x|y\n10|20";
  const result = parseCSV(csv, { delimiter: "|" });
  assertDeepEqual(result.rows[0], { x: 10, y: 20 }, "pipe row");
});

test("custom quote character (single quote)", () => {
  const csv = "name,city\n'Alice','New York, NY'";
  const result = parseCSV(csv, { quote: "'" });
  assertStrictEqual(result.rows[0]["city"], "New York, NY", "single-quote enclosed");
});

test("custom line separator", () => {
  const csv = "a,b|1,2|3,4";
  const result = parseCSV(csv, { lineSeparator: "|" });
  assertStrictEqual(result.rows.length, 2, "custom line sep row count");
  assertDeepEqual(result.rows[0], { a: 1, b: 2 }, "custom sep row 0");
});

// ---------------------------------------------------------------------------
section("Type Coercion");
// ---------------------------------------------------------------------------

test("integers", () => {
  const csv = "val\n0\n42\n-7\n1000000";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], 0, "zero");
  assertStrictEqual(result.rows[1]["val"], 42, "positive int");
  assertStrictEqual(result.rows[2]["val"], -7, "negative int");
  assertStrictEqual(result.rows[3]["val"], 1000000, "large int");
});

test("floats", () => {
  const csv = "val\n3.14\n-0.5\n.25\n1e10\n2.5e-3";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], 3.14, "pi-ish");
  assertStrictEqual(result.rows[1]["val"], -0.5, "negative float");
  assertStrictEqual(result.rows[2]["val"], 0.25, "leading dot");
  assertStrictEqual(result.rows[3]["val"], 1e10, "scientific");
  assertStrictEqual(result.rows[4]["val"], 2.5e-3, "scientific neg exp");
});

test("booleans (case-insensitive)", () => {
  const csv = "val\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], true, "true");
  assertStrictEqual(result.rows[1]["val"], false, "false");
  assertStrictEqual(result.rows[2]["val"], true, "TRUE");
  assertStrictEqual(result.rows[3]["val"], false, "FALSE");
  assertStrictEqual(result.rows[4]["val"], true, "True");
  assertStrictEqual(result.rows[5]["val"], false, "False");
});

test("null values", () => {
  const csv = "val\nnull\nNULL\n";
  // Last line is blank → skipped; we need a real empty field row
  const csv2 = "a,b\nnull,NULL\n,something";
  const result = parseCSV(csv2);
  assertStrictEqual(result.rows[0]["a"], null, "null");
  assertStrictEqual(result.rows[0]["b"], null, "NULL");
  assertStrictEqual(result.rows[1]["a"], null, "empty string → null");
});

test("strings that look numeric-ish but are not", () => {
  const csv = "val\n12abc\nabc\n12.34.56\n--5";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], "12abc", "12abc stays string");
  assertStrictEqual(result.rows[1]["val"], "abc", "abc stays string");
  assertStrictEqual(result.rows[2]["val"], "12.34.56", "double-dot stays string");
  assertStrictEqual(result.rows[3]["val"], "--5", "double-neg stays string");
});

test("type coercion can be disabled", () => {
  const csv = "val\n42\ntrue\nnull";
  const result = parseCSV(csv, { typeCoercion: false });
  assertStrictEqual(result.rows[0]["val"], "42", "42 stays string");
  assertStrictEqual(result.rows[1]["val"], "true", "true stays string");
  assertStrictEqual(result.rows[2]["val"], "null", "null stays string");
});

// ---------------------------------------------------------------------------
section("Malformed Row Error Collection");
// ---------------------------------------------------------------------------

test("row with too few columns collects error but still parses", () => {
  const csv = "a,b,c\n1,2,3\n4,5\n6,7,8";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 3, "all rows parsed");
  assert(result.errors.length > 0, "errors collected");
  assert(
    result.errors.some((e) => e.message.includes("Column count mismatch")),
    "mismatch error message"
  );
  // The short row should still have headers filled (missing → null via coerce(""))
  assertStrictEqual(result.rows[1]["c"], null, "missing field → null");
});

test("row with too many columns collects error but still parses", () => {
  const csv = "a,b\n1,2\n3,4,5";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "both rows parsed");
  assert(result.errors.length > 0, "errors collected");
  assert(
    result.errors.some((e) => e.message.includes("Column count mismatch")),
    "mismatch error"
  );
});

test("unterminated quoted field collects error", () => {
  const csv = 'a,b\n"hello,world';
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "has errors");
  assert(
    result.errors.some((e) => e.message.includes("Unterminated quoted field")),
    "unterminated error"
  );
});

test("multiple malformed rows collect multiple errors", () => {
  const csv = "a,b,c\n1\n2\n3,4,5";
  const result = parseCSV(csv);
  // Rows at index 1 and 2 are malformed
  const mismatchErrors = result.errors.filter((e) =>
    e.message.includes("Column count mismatch")
  );
  assert(mismatchErrors.length >= 2, "at least 2 mismatch errors");
});

test("error objects contain correct row numbers", () => {
  const csv = "a,b\n1,2\nBAD\n3,4";
  const result = parseCSV(csv);
  const err = result.errors.find((e) => e.row === 2);
  assert(err !== undefined, "error on row index 2");
});

// ---------------------------------------------------------------------------
section("Filter");
// ---------------------------------------------------------------------------

test("filter returns matching rows", () => {
  const csv = "name,age\nAlice,30\nBob,25\nCharlie,35";
  const result = parseCSV(csv);
  const older = result.filter((r) => (r["age"] as number) >= 30);
  assertStrictEqual(older.length, 2, "filtered count");
  assertStrictEqual(older[0]["name"], "Alice", "first match");
  assertStrictEqual(older[1]["name"], "Charlie", "second match");
});

test("filter with no matches returns empty array", () => {
  const csv = "val\n1\n2\n3";
  const result = parseCSV(csv);
  const none = result.filter((r) => (r["val"] as number) > 100);
  assertStrictEqual(none.length, 0, "no matches");
});

test("filter with string predicate", () => {
  const csv = "fruit,qty\napple,5\nbanana,3\napple,2";
  const result = parseCSV(csv);
  const apples = result.filter((r) => r["fruit"] === "apple");
  assertStrictEqual(apples.length, 2, "apple rows");
});

// ---------------------------------------------------------------------------
section("Aggregation — sum");
// ---------------------------------------------------------------------------

test("sum of numeric column", () => {
  const csv = "item,price\nA,10\nB,20.5\nC,30";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("price"), 60.5, "sum price");
});

test("sum ignores non-numeric values", () => {
  const csv = "val\n10\nhello\n20\nnull";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("val"), 30, "sum with non-numerics");
});

test("sum of non-existent column is 0", () => {
  const csv = "a\n1";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("z"), 0, "missing column sum");
});

test("sum with negative numbers", () => {
  const csv = "val\n10\n-3\n-7\n5";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("val"), 5, "sum with negatives");
});

// ---------------------------------------------------------------------------
section("Aggregation — average");
// ---------------------------------------------------------------------------

test("average of numeric column", () => {
  const csv = "val\n10\n20\n30";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("val"), 20, "average");
});

test("average ignores non-numeric values", () => {
  const csv = "val\n10\nhello\n30";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("val"), 20, "average skipping strings");
});

test("average of empty data is 0", () => {
  const csv = "val";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("val"), 0, "average of no rows");
});

test("average of column with no numerics is 0", () => {
