// csv-parser.js — Transpiled from csv-parser.ts

function parseRow(line, delimiter, quote) {
  if (line.length === 0) return null;

  const fields = [];
  let i = 0;

  while (i <= line.length) {
    if (i === line.length) {
      break;
    }

    if (line[i] === quote) {
      i++;
      let value = "";
      let closed = false;
      while (i < line.length) {
        if (line[i] === quote) {
          if (i + 1 < line.length && line[i + 1] === quote) {
            value += quote;
            i += 2;
          } else {
            i++;
            closed = true;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }

      if (!closed) {
        fields.push(value);
        return { fields, error: "Unterminated quoted field" };
      }

      fields.push(value);

      if (i < line.length) {
        if (line[i] === delimiter) {
          i++;
          if (i === line.length) {
            fields.push("");
          }
        } else {
          let junk = "";
          while (i < line.length && line[i] !== delimiter) {
            junk += line[i];
            i++;
          }
          fields[fields.length - 1] += junk;
          if (i < line.length) {
            i++;
            if (i === line.length) {
              fields.push("");
            }
          }
        }
      }
    } else {
      let value = "";
      while (i < line.length && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);
      if (i < line.length) {
        i++;
        if (i === line.length) {
          fields.push("");
        }
      }
    }
  }

  return { fields };
}

function coerce(value) {
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  if (/^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(value.trim())) {
    const num = Number(value);
    if (!Number.isNaN(num)) return num;
  }

  return value;
}

function detectLineSeparator(input) {
  let inQuotes = false;
  for (let i = 0; i < input.length; i++) {
    if (input[i] === '"') {
      if (inQuotes && i + 1 < input.length && input[i + 1] === '"') {
        i++;
        continue;
      }
      inQuotes = !inQuotes;
      continue;
    }
    if (!inQuotes) {
      if (input[i] === "\r") {
        return i + 1 < input.length && input[i + 1] === "\n" ? "\r\n" : "\r";
      }
      if (input[i] === "\n") return "\n";
    }
  }
  return "\n";
}

function splitLines(input, lineSep, quote) {
  const lines = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  const sep = lineSep !== undefined && lineSep !== null ? lineSep : detectLineSeparator(input);

  while (i < input.length) {
    if (input[i] === quote) {
      if (inQuotes && i + 1 < input.length && input[i + 1] === quote) {
        current += input[i] + input[i + 1];
        i += 2;
        continue;
      }
      inQuotes = !inQuotes;
      current += input[i];
      i++;
      continue;
    }

    if (!inQuotes && input.startsWith(sep, i)) {
      lines.push(current);
      current = "";
      i += sep.length;
      continue;
    }

    current += input[i];
    i++;
  }

  lines.push(current);
  return lines;
}

function buildResult(headers, rows, errors) {
  return {
    headers,
    rows,
    errors,

    filter(predicate) {
      return rows.filter(predicate);
    },

    sum(column) {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column) {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count() {
      return rows.length;
    },

    groupBy(column) {
      const map = new Map();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

function parseCSV(input, options) {
  options = options || {};
  const delimiter = options.delimiter || ",";
  const quote = options.quote || '"';
  const lineSeparator = options.lineSeparator;
  const shouldCoerce = options.typeCoercion !== false;

  const errors = [];
  const rows = [];

  if (input.trim().length === 0) {
    return buildResult([], [], errors);
  }

  const lines = splitLines(input, lineSeparator, quote);

  const headerResult = parseRow(lines[0], delimiter, quote);
  if (!headerResult || headerResult.fields.length === 0) {
    return buildResult([], [], [{ row: 0, message: "Missing or empty header row" }]);
  }
  if (headerResult.error) {
    errors.push({ row: 0, message: "Header row: " + headerResult.error });
  }
  const headers = headerResult.fields.map((h) => h.trim());

  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];

    if (line.length === 0 && idx === lines.length - 1) continue;
    if (line.trim().length === 0) continue;

    const result = parseRow(line, delimiter, quote);
    if (result === null) continue;

    if (result.error) {
      errors.push({ row: idx, message: result.error });
    }

    const fields = result.fields;

    if (fields.length !== headers.length) {
      errors.push({
        row: idx,
        message: "Column count mismatch: expected " + headers.length + ", got " + fields.length,
      });
    }

    const row = {};
    for (let c = 0; c < headers.length; c++) {
      const raw = c < fields.length ? fields[c] : "";
      row[headers[c]] = shouldCoerce ? coerce(raw) : raw;
    }
    rows.push(row);
  }

  return buildResult(headers, rows, errors);
}

// Export for the test file
if (typeof module !== "undefined") {
  module.exports = { parseCSV };
}

