const { parseCSV } = require("./csv-parser.js");

let passed = 0;
let failed = 0;
const failures = [];

function assert(condition, msg) {
  if (!condition) throw new Error("Assertion failed: " + msg);
}

function assertStrictEqual(actual, expected, label) {
  if (actual !== expected) {
    throw new Error(
      label + " — expected " + JSON.stringify(expected) + ", got " + JSON.stringify(actual)
    );
  }
}

function replacer(_key, value) {
  if (value instanceof Map) {
    return Object.fromEntries(value.entries());
  }
  return value;
}

function assertDeepEqual(actual, expected, label) {
  const a = JSON.stringify(actual, replacer);
  const b = JSON.stringify(expected, replacer);
  if (a !== b) {
    throw new Error(label + "\n  expected: " + b + "\n  actual:   " + a);
  }
}

function test(name, fn) {
  try {
    fn();
    passed++;
    console.log("  ✅ " + name);
  } catch (err) {
    failed++;
    const msg = "  ❌ " + name + ": " + err.message;
    failures.push(msg);
    console.log(msg);
  }
}

function section(title) {
  console.log("\n── " + title + " " + "─".repeat(Math.max(0, 60 - title.length)));
}

