test("integers", function () {
  const csv = "val\n0\n42\n-7\n1000000";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], 0, "zero");
  assertStrictEqual(result.rows[1]["val"], 42, "positive int");
  assertStrictEqual(result.rows[2]["val"], -7, "negative int");
  assertStrictEqual(result.rows[3]["val"], 1000000, "large int");
});

test("floats", function () {
  const csv = "val\n3.14\n-0.5\n.25\n1e10\n2.5e-3";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], 3.14, "pi-ish");
  assertStrictEqual(result.rows[1]["val"], -0.5, "negative float");
  assertStrictEqual(result.rows[2]["val"], 0.25, "leading dot");
  assertStrictEqual(result.rows[3]["val"], 1e10, "scientific");
  assertStrictEqual(result.rows[4]["val"], 2.5e-3, "scientific neg exp");
});

test("booleans (case-insensitive)", function () {
  const csv = "val\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], true, "true");
  assertStrictEqual(result.rows[1]["val"], false, "false");
  assertStrictEqual(result.rows[2]["val"], true, "TRUE");
  assertStrictEqual(result.rows[3]["val"], false, "FALSE");
  assertStrictEqual(result.rows[4]["val"], true, "True");
  assertStrictEqual(result.rows[5]["val"], false, "False");
});

test("null values", function () {
  const csv2 = "a,b\nnull,NULL\n,something";
  const result = parseCSV(csv2);
  assertStrictEqual(result.rows[0]["a"], null, "null");
  assertStrictEqual(result.rows[0]["b"], null, "NULL");
  assertStrictEqual(result.rows[1]["a"], null, "empty string → null");
});

test("strings that look numeric-ish but are not", function () {
  const csv = "val\n12abc\nabc\n12.34.56\n--5";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], "12abc", "12abc stays string");
  assertStrictEqual(result.rows[1]["val"], "abc", "abc stays string");
  assertStrictEqual(result.rows[2]["val"], "12.34.56", "double-dot stays string");
  assertStrictEqual(result.rows[3]["val"], "--5", "double-neg stays string");
});

test("type coercion can be disabled", function () {
  const csv = "val\n42\ntrue\nnull";
  const result = parseCSV(csv, { typeCoercion: false });
  assertStrictEqual(result.rows[0]["val"], "42", "42 stays string");
  assertStrictEqual(result.rows[1]["val"], "true", "true stays string");
  assertStrictEqual(result.rows[2]["val"], "null", "null stays string");
});

// ---------------------------------------------------------------------------
section("Malformed Row Error Collection");
// ---------------------------------------------------------------------------

test("row with too few columns collects error but still parses", function () {
  const csv = "a,b,c\n1,2,3\n4,5\n6,7,8";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 3, "all rows parsed");
  assert(result.errors.length > 0, "errors collected");
  assert(
    result.errors.some(function (e) { return e.message.includes("Column count mismatch"); }),
    "mismatch error message"
  );
  assertStrictEqual(result.rows[1]["c"], null, "missing field → null");
});

test("row with too many columns collects error but still parses", function () {
  const csv = "a,b\n1,2\n3,4,5";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "both rows parsed");
  assert(result.errors.length > 0, "errors collected");
  assert(
    result.errors.some(function (e) { return e.message.includes("Column count mismatch"); }),
    "mismatch error"
  );
});

test("unterminated quoted field collects error", function () {
  const csv = 'a,b\n"hello,world';
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "has errors");
  assert(
    result.errors.some(function (e) { return e.message.includes("Unterminated quoted field"); }),
    "unterminated error"
  );
});

test("multiple malformed rows collect multiple errors", function () {
  const csv = "a,b,c\n1\n2\n3,4,5";
  const result = parseCSV(csv);
  const mismatchErrors = result.errors.filter(function (e) {
    return e.message.includes("Column count mismatch");
  });
  assert(mismatchErrors.length >= 2, "at least 2 mismatch errors");
});

test("error objects contain correct row numbers", function () {
  const csv = "a,b\n1,2\nBAD\n3,4";
  const result = parseCSV(csv);
  const err = result.errors.find(function (e) { return e.row === 2; });
  assert(err !== undefined, "error on row index 2");
});

// ---------------------------------------------------------------------------
section("Filter");
// ---------------------------------------------------------------------------

test("filter returns matching rows", function () {
  const csv = "name,age\nAlice,30\nBob,25\nCharlie,35";
  const result = parseCSV(csv);
  const older = result.filter(function (r) { return r["age"] >= 30; });
  assertStrictEqual(older.length, 2, "filtered count");
  assertStrictEqual(older[0]["name"], "Alice", "first match");
  assertStrictEqual(older[1]["name"], "Charlie", "second match");
});

test("filter with no matches returns empty array", function () {
  const csv = "val\n1\n2\n3";
  const result = parseCSV(csv);
  const none = result.filter(function (r) { return r["val"] > 100; });
  assertStrictEqual(none.length, 0, "no matches");
});

test("filter with string predicate", function () {
  const csv = "fruit,qty\napple,5\nbanana,3\napple,2";
  const result = parseCSV(csv);
  const apples = result.filter(function (r) { return r["fruit"] === "apple"; });
  assertStrictEqual(apples.length, 2, "apple rows");
});

// ---------------------------------------------------------------------------
section("Aggregation — sum");
// ---------------------------------------------------------------------------

test("sum of numeric column", function () {
  const csv = "item,price\nA,10\nB,20.5\nC,30";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("price"), 60.5, "sum price");
});

test("sum ignores non-numeric values", function () {
  const csv = "val\n10\nhello\n20\nnull";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("val"), 30, "sum with non-numerics");
});

test("sum of non-existent column is 0", function () {
  const csv = "a\n1";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("z"), 0, "missing column sum");
});

test("sum with negative numbers", function () {
  const csv = "val\n10\n-3\n-7\n5";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("val"), 5, "sum with negatives");
});

// ---------------------------------------------------------------------------
section("Aggregation — average");
// ---------------------------------------------------------------------------

test("average of numeric column", function () {
  const csv = "val\n10\n20\n30";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("val"), 20, "average");
});

test("average ignores non-numeric values", function () {
  const csv = "val\n10\nhello\n30";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("val"), 20, "average skipping strings");
});

test("average of empty data is 0", function () {
  const csv = "val";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("val"), 0, "average of no rows");
});

test("average of column with no numerics is 0", function () {
  const csv = "val\nhello\nworld";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("val"), 0, "average no numerics");
});

// ---------------------------------------------------------------------------
section("Aggregation — count");
// ---------------------------------------------------------------------------

test("count returns number of data rows", function () {
  const csv = "a\n1\n2\n3\n4\n5";
  const result = parseCSV(csv);
  assertStrictEqual(result.count(), 5, "count");
});

test("count with zero rows", function () {
  const csv = "a,b,c";
  const result = parseCSV(csv);
  assertStrictEqual(result.count(), 0, "count zero");
});

// ---------------------------------------------------------------------------
section("Aggregation — groupBy");
// ---------------------------------------------------------------------------

test("groupBy groups rows by column value", function () {
  const csv = "dept,name\nEng,Alice\nHR,Bob\nEng,Charlie\nHR,Diana";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assert(groups instanceof Map, "returns Map");
  assertStrictEqual(groups.size, 2, "two groups");
  assertStrictEqual(groups.get("Eng").length, 2, "Eng group size");
  assertStrictEqual(groups.get("HR").length, 2, "HR group size");
  assertStrictEqual(groups.get("Eng")[0]["name"], "Alice", "first Eng member");
});

test("groupBy with numeric keys", function () {
  const csv = "score,name\n100,Alice\n90,Bob\n100,Charlie";
  const result = parseCSV(csv);
  const groups = result.groupBy("score");
  assertStrictEqual(groups.get(100).length, 2, "score=100 group size");
  assertStrictEqual(groups.get(90).length, 1, "score=90 group size");
});

test("groupBy with null values", function () {
  const csv = "category,val\nA,1\n,2\nA,3\n,4";
  const result = parseCSV(csv);
  const groups = result.groupBy("category");
  assertStrictEqual(groups.get("A").length, 2, "A group");
  assertStrictEqual(groups.get(null).length, 2, "null group");
});

// ---------------------------------------------------------------------------
section("Edge Cases");
// ---------------------------------------------------------------------------

test("empty input returns empty result", function () {
  const result = parseCSV("");
  assertStrictEqual(result.headers.length, 0, "no headers");
  assertStrictEqual(result.rows.length, 0, "no rows");
  assertStrictEqual(result.errors.length, 0, "no errors");
});

test("whitespace-only input returns empty result", function () {
  const result = parseCSV("   \n  \n  ");
  assertStrictEqual(result.headers.length, 0, "no headers");
  assertStrictEqual(result.rows.length, 0, "no rows");
});

test("single column CSV", function () {
  const csv = "value\nhello\nworld";
  const result = parseCSV(csv);
  assertStrictEqual(result.headers.length, 1, "one header");
  assertStrictEqual(result.rows.length, 2, "two rows");
  assertStrictEqual(result.rows[0]["value"], "hello", "row 0");
});

test("single row (header only, no data)", function () {
  const csv = "a,b,c";
  const result = parseCSV(csv);
  assertDeepEqual(result.headers, ["a", "b", "c"], "headers");
  assertStrictEqual(result.rows.length, 0, "no data rows");
});

test("single data row", function () {
  const csv = "x\n42";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 1, "one row");
  assertStrictEqual(result.rows[0]["x"], 42, "value");
});

test("very large field (10 000 characters)", function () {
  const bigValue = "A".repeat(10000);
  const csv = "col\n" + bigValue;
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["col"].length, 10000, "large field length");
});

test("very large quoted field with commas and newlines", function () {
  const inner = ("word," + "more\n").repeat(500);
  const csv = 'data\n"' + inner + '"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 1, "one row");
  assert(result.rows[0]["data"].includes("word,"), "contains comma");
});

test("many columns", function () {
  const n = 200;
  const headers = Array.from({ length: n }, function (_, i) { return "c" + i; }).join(",");
  const values = Array.from({ length: n }, function (_, i) { return String(i); }).join(",");
  const csv = headers + "\n" + values;
  const result = parseCSV(csv);
  assertStrictEqual(result.headers.length, n, "header count");
  assertStrictEqual(result.rows[0]["c0"], 0, "first col");
  assertStrictEqual(result.rows[0]["c" + (n - 1)], n - 1, "last col");
});

test("many rows", function () {
  const lines = ["val"];
  for (let i = 0; i < 1000; i++) lines.push(String(i));
  const csv = lines.join("\n");
  const result = parseCSV(csv);
  assertStrictEqual(result.count(), 1000, "1000 rows");
  assertStrictEqual(result.sum("val"), (999 * 1000) / 2, "sum 0..999");
});

test("field with only whitespace is kept as string", function () {
  const csv = "val\n   ";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], "   ", "whitespace field");
});

test("quoted field preserving leading/trailing spaces", function () {
  const csv = 'val\n"  spaced  "';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], "  spaced  ", "spaces preserved");
});

test("completely empty fields in the middle", function () {
  const csv = "a,b,c\n1,,3";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["b"], null, "empty middle field → null");
});

test("trailing delimiter produces empty field", function () {
  const csv = "a,b\n1,\n,2";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["b"], null, "trailing delim → null");
  assertStrictEqual(result.rows[1]["a"], null, "leading delim → null");
});

test("row with only delimiters", function () {
  const csv = "a,b,c\n,,";
  const result = parseCSV(csv);
  assertDeepEqual(result.rows[0], { a: null, b: null, c: null }, "all nulls");
});

test("mixed quoting in a single row", function () {
  const csv = 'a,b,c\n"quoted",plain,"also, quoted"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["a"], "quoted", "first quoted");
  assertStrictEqual(result.rows[0]["b"], "plain", "middle unquoted");
  assertStrictEqual(result.rows[0]["c"], "also, quoted", "last quoted w/ comma");
});

test("number-like values inside quotes are still coerced", function () {
  const csv = 'val\n"42"\n"3.14"\n"true"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], 42, "quoted number");
  assertStrictEqual(result.rows[1]["val"], 3.14, "quoted float");
  assertStrictEqual(result.rows[2]["val"], true, "quoted boolean");
});

test("combined custom options: semicolon delimiter + single-quote + custom line sep", function () {
  const csv = "a;b|'hello, world';42";
  const result = parseCSV(csv, { delimiter: ";", quote: "'", lineSeparator: "|" });
  assertStrictEqual(result.rows[0]["a"], "hello, world", "custom combo field a");
  assertStrictEqual(result.rows[0]["b"], 42, "custom combo field b");
});

// ---------------------------------------------------------------------------
section("Interaction: filter + aggregation on same result");
// ---------------------------------------------------------------------------

test("filter then manual sum on filtered subset", function () {
  const csv = "dept,salary\nEng,100\nHR,50\nEng,120\nHR,60";
  const result = parseCSV(csv);
  const engRows = result.filter(function (r) { return r["dept"] === "Eng"; });
  const engSum = engRows.reduce(function (s, r) { return s + r["salary"]; }, 0);
  assertStrictEqual(engSum, 220, "eng salary sum via filter");
});

test("groupBy then sum per group", function () {
  const csv = "dept,salary\nEng,100\nHR,50\nEng,120\nHR,60";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  const engTotal = groups
    .get("Eng")
    .reduce(function (s, r) { return s + r["salary"]; }, 0);
  const hrTotal = groups
    .get("HR")
    .reduce(function (s, r) { return s + r["salary"]; }, 0);

  assertStrictEqual(engTotal, 220, "Eng total");
  assertStrictEqual(hrTotal, 110, "HR total");
});

// ---------------------------------------------------------------------------
// Summary
// ---------------------------------------------------------------------------

console.log("\n" + "═".repeat(64));
console.log("  Tests: " + passed + " passed, " + failed + " failed, " + (passed + failed) + " total");
if (failures.length) {
  console.log("\nFailures:");
  failures.forEach(function (f) { console.log(f); });
  process.exit(1);
} else {
  console.log("  All tests passed! 🎉");
}

