// csv-parser.test.ts — Comprehensive tests for the CSV parser library
// No external test framework — plain assertions that throw on failure.

import { parseCSV, CSVResult } from "./csv-parser";

// ---------------------------------------------------------------------------
// Tiny test harness
// ---------------------------------------------------------------------------

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, msg: string): void {
  if (!condition) throw new Error(`Assertion failed: ${msg}`);
}

function assertStrictEqual<T>(actual: T, expected: T, label: string): void {
  if (actual !== expected) {
    throw new Error(
      `${label} — expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`
    );
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual, replacer);
  const b = JSON.stringify(expected, replacer);
  if (a !== b) {
    throw new Error(`${label}\n  expected: ${b}\n  actual:   ${a}`);
  }
}

// JSON.stringify replacer that handles Map, undefined, etc.
function replacer(_key: string, value: unknown): unknown {
  if (value instanceof Map) {
    return Object.fromEntries(value.entries());
  }
  return value;
}

function test(name: string, fn: () => void): void {
  try {
    fn();
    passed++;
    console.log(`  ✅ ${name}`);
  } catch (err: any) {
    failed++;
    const msg = `  ❌ ${name}: ${err.message}`;
    failures.push(msg);
    console.log(msg);
  }
}

function section(title: string): void {
  console.log(`\n── ${title} ${"─".repeat(60 - title.length)}`);
}

// ===========================================================================
// TESTS
// ===========================================================================

// ---------------------------------------------------------------------------
section("Basic Parsing");
// ---------------------------------------------------------------------------

test("parses simple CSV with headers", () => {
  const csv = "name,age,city\nAlice,30,NYC\nBob,25,LA";
  const result = parseCSV(csv);

  assertStrictEqual(result.headers.length, 3, "header count");
  assertDeepEqual(result.headers, ["name", "age", "city"], "headers");
  assertStrictEqual(result.rows.length, 2, "row count");
  assertDeepEqual(result.rows[0], { name: "Alice", age: 30, city: "NYC" }, "row 0");
  assertDeepEqual(result.rows[1], { name: "Bob", age: 25, city: "LA" }, "row 1");
  assertStrictEqual(result.errors.length, 0, "no errors");
});

test("handles Windows-style line endings (\\r\\n)", () => {
  const csv = "a,b\r\n1,2\r\n3,4";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertDeepEqual(result.rows[0], { a: 1, b: 2 }, "row 0");
  assertDeepEqual(result.rows[1], { a: 3, b: 4 }, "row 1");
});

test("handles old Mac line endings (\\r)", () => {
  const csv = "x,y\r10,20\r30,40";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertDeepEqual(result.rows[0], { x: 10, y: 20 }, "row 0");
});

test("trims header names", () => {
  const csv = " name , age \nAlice,30";
  const result = parseCSV(csv);
  assertDeepEqual(result.headers, ["name", "age"], "trimmed headers");
});

test("trailing newline does not create an extra row", () => {
  const csv = "a,b\n1,2\n";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 1, "row count");
});

// ---------------------------------------------------------------------------
section("Quoted Fields");
// ---------------------------------------------------------------------------

test("handles quoted fields that contain commas", () => {
  const csv = 'name,address\nAlice,"123 Main St, Apt 4"\nBob,"456 Oak Ave, Suite 7"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["address"], "123 Main St, Apt 4", "address with comma");
  assertStrictEqual(result.rows[1]["address"], "456 Oak Ave, Suite 7", "address with comma");
});

test("handles quoted fields that contain newlines", () => {
  const csv = 'name,bio\nAlice,"Line 1\nLine 2"\nBob,simple';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertStrictEqual(result.rows[0]["bio"], "Line 1\nLine 2", "bio with newline");
  assertStrictEqual(result.rows[1]["bio"], "simple", "simple bio");
});

test("quoted field at beginning and end of row", () => {
  const csv = '"greeting",middle,"farewell"\n"hello",x,"bye"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["greeting"], "hello", "first field quoted");
  assertStrictEqual(result.rows[0]["farewell"], "bye", "last field quoted");
});

test("empty quoted field", () => {
  const csv = 'a,b\n"",value';
  const result = parseCSV(csv);
  // An empty quoted string should coerce to null (same as empty string)
  assertStrictEqual(result.rows[0]["a"], null, "empty quoted field → null");
});

// ---------------------------------------------------------------------------
section("Escaped Quotes");
// ---------------------------------------------------------------------------

test("double-double-quotes inside quoted field become single quote", () => {
  const csv = 'text\n"She said ""hello"""\n"A ""B"" C"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["text"], 'She said "hello"', "escaped quotes 1");
  assertStrictEqual(result.rows[1]["text"], 'A "B" C', "escaped quotes 2");
});

test("field that is just escaped quotes", () => {
  const csv = 'val\n""""""';
  // """""" → content is "" → literal: ""
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["val"], '""', "only escaped quotes");
});

