section("Malformed Row Error Collection");
// ---------------------------------------------------------------------------

test("row with too few columns collects error but still parses", () => {
  const csv = "a,b,c\n1,2,3\n4,5\n6,7,8";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 3, "all rows parsed");
  assert(result.errors.length > 0, "errors collected");
  assert(
    result.errors.some((e) => e.message.includes("Column count mismatch")),
    "mismatch error message"
  );
  // The short row should still have headers filled (missing → null via coerce(""))
  assertStrictEqual(result.rows[1]["c"], null, "missing field → null");
});

test("row with too many columns collects error but still parses", () => {
  const csv = "a,b\n1,2\n3,4,5";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "both rows parsed");
  assert(result.errors.length > 0, "errors collected");
  assert(
    result.errors.some((e) => e.message.includes("Column count mismatch")),
    "mismatch error"
  );
});

test("unterminated quoted field collects error", () => {
  const csv = 'a,b\n"hello,world';
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "has errors");
  assert(
    result.errors.some((e) => e.message.includes("Unterminated quoted field")),
    "unterminated error"
  );
});

test("multiple malformed rows collect multiple errors", () => {
  const csv = "a,b,c\n1\n2\n3,4,5";
  const result = parseCSV(csv);
  // Rows at index 1 and 2 are malformed
  const mismatchErrors = result.errors.filter((e) =>
    e.message.includes("Column count mismatch")
  );
  assert(mismatchErrors.length >= 2, "at least 2 mismatch errors");
});

test("error objects contain correct row numbers", () => {
  const csv = "a,b\n1,2\nBAD\n3,4";
  const result = parseCSV(csv);
  const err = result.errors.find((e) => e.row === 2);
  assert(err !== undefined, "error on row index 2");
});

