section("Interaction: filter + aggregation on same result");

test("filter then manual sum on filtered subset", () => {
  const csv = "dept,salary\nEng,100\nHR,50\nEng,120\nHR,60";
  const result = parseCSV(csv);
  const engRows = result.filter((r) => r["dept"] === "Eng");
  const engSum = engRows.reduce((s, r) => s + (r["salary"] as number), 0);
  assertStrictEqual(engSum, 220, "eng salary sum via filter");
});

test("groupBy then sum per group", () => {
  const csv = "dept,salary\nEng,100\nHR,50\nEng,120\nHR,60";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  const engTotal = groups
    .get("Eng")!
    .reduce((s, r) => s + (r["salary"] as number), 0);
  const hrTotal = groups
    .get("HR")!
    .reduce((s, r) => s + (r["salary"] as number), 0);

  assertStrictEqual(engTotal, 220, "Eng total");
  assertStrictEqual(hrTotal, 110, "HR total");
});

